class Solution:
    def minDistance(self, word1, word2):
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(100000)
        @lru_cache(None)
        def f(i, j):
            if i == 0:
                return j
            if j == 0:
                return i
            if word1[i - 1] == word2[j - 1]:
                return f(i - 1, j - 1)
            return 1 + min(f(i - 1, j), f(i, j - 1), f(i - 1, j - 1))
        return f(len(word1), len(word2))

